> +	ret = bus_dmamap_load(dmah->tag, dmah->map, dmah->vaddr,
> +	    gart_info->table_size, drm_ati_alloc_pcigart_table_cb, dmah, 0);
> +	if (ret != 0) {
> +		bus_dmamem_free(dmah->tag, dmah->vaddr, dmah->map);
> +		bus_dma_tag_destroy(dmah->tag);
> +		free(dmah, M_DRM);
>  		return ENOMEM;
> +	}
> +	dev->sg->dmah = dmah;
>  
>  	return 0;
>  }
